import { useNavigate } from 'react-router-dom';
import '../styles/Groups.css'; // ou Tailwind

export default function DestinationCards({ id, name, image, price, startDate, endDate, creator, comments = [] }) {
    const navigate = useNavigate();

    // Calcul de la note moyenne
    const averageRating =
        comments.length > 0
            ? (comments.reduce((sum, c) => sum + (parseInt(c.rating) || 0), 0) / comments.length).toFixed(1)
            : '—';

    return (
        <div className="group-card" onClick={() => navigate(`/groups/${id}`)}>
            <img src={image} alt={name} className="group-image" />

            <div className="group-info">
                <h2 className="group-name">{name}</h2>

                {/* Note moyenne */}
                <p className="group-rating">
                    <strong>{averageRating}</strong> ⭐
                </p>

                {/* Prix */}
                {price && (
                    <p className="group-price">
                        <strong>Prix :</strong> {price} €
                    </p>
                )}

                {/* Dates */}
                {(startDate || endDate) && (
                    <p className="group-dates">
                        <strong>Dates :</strong> {startDate} → {endDate}
                    </p>
                )}

                {/* Créateur */}
                {creator && (
                    <p className="group-creator">
                        <strong>Proposé par :</strong> {creator}
                    </p>
                )}
            </div>
        </div>
    );
}
